import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import Navbar from '../components/Navbar';
import LoadingSpinner from '../components/LoadingSpinner';

const MyProperties = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMyProperties();
  }, []);

  const fetchMyProperties = async () => {
    try {
      const response = await axios.get('/properties/my-properties');
      setProperties(response.data);
    } catch (error) {
      console.error('Error fetching properties:', error);
      toast.error('Failed to fetch properties');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this property?')) {
      try {
        await axios.delete(`/properties/${id}`);
        toast.success('Property deleted successfully');
        fetchMyProperties();
      } catch (error) {
        toast.error('Failed to delete property');
      }
    }
  };

  const handleMarkAsSold = async (id, status) => {
    try {
      await axios.put(`/properties/${id}/mark-sold`, { status });
      toast.success(`Property marked as ${status}`);
      fetchMyProperties();
    } catch (error) {
      toast.error('Failed to update property status');
    }
  };

  const getStatusBadge = (status) => {
    const colors = {
      pending: 'bg-yellow-500',
      approved: 'bg-green-500',
      rejected: 'bg-red-500',
      sold: 'bg-gray-500',
      rented: 'bg-blue-500'
    };
    return (
      <span className={`px-2 py-1 rounded text-xs font-semibold text-white ${colors[status]}`}>
        {status.toUpperCase()}
      </span>
    );
  };

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <Navbar />
      <div className="container mx-auto px-4 py-8">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold">My Properties</h1>
          <Link to="/add-property" className="btn-primary">
            Add New Property
          </Link>
        </div>

        {properties.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-lg shadow">
            <p className="text-gray-500 text-lg">You haven't listed any properties yet.</p>
            <Link to="/add-property" className="btn-primary inline-block mt-4">
              List Your First Property
            </Link>
          </div>
        ) : (
          <div className="grid gap-6">
            {properties.map(property => (
              <div key={property._id} className="bg-white rounded-lg shadow-lg overflow-hidden">
                <div className="md:flex">
                  <div className="md:w-64 h-48 md:h-auto">
                    {property.images && property.images.length > 0 ? (
                      <img
                        src={property.images[0]}
                        alt={property.title}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <div className="w-full h-full bg-gray-200 flex items-center justify-center">
                        <span className="text-gray-400">No image</span>
                      </div>
                    )}
                  </div>
                  <div className="p-6 flex-1">
                    <div className="flex justify-between items-start">
                      <div>
                        <h3 className="text-xl font-semibold text-gray-800 mb-2">{property.title}</h3>
                        <p className="text-gray-600 mb-2">{property.location}</p>
                        <p className="text-2xl font-bold text-blue-600 mb-2">
                          ${property.price.toLocaleString()}
                          {property.listingType === 'rent' && '/month'}
                        </p>
                        <div className="flex space-x-2 mb-3">
                          {getStatusBadge(property.status)}
                          <span className={`px-2 py-1 rounded text-xs font-semibold ${
                            property.listingType === 'sale' ? 'bg-green-100 text-green-800' : 'bg-blue-100 text-blue-800'
                          }`}>
                            {property.listingType.toUpperCase()}
                          </span>
                        </div>
                      </div>
                      <div className="flex space-x-2">
                        <Link
                          to={`/edit-property/${property._id}`}
                          className="bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600"
                        >
                          Edit
                        </Link>
                        <button
                          onClick={() => handleDelete(property._id)}
                          className="bg-red-500 text-white px-3 py-1 rounded hover:bg-red-600"
                        >
                          Delete
                        </button>
                      </div>
                    </div>
                    <div className="flex space-x-4 mt-4">
                      {property.status === 'approved' && property.listingType === 'sale' && (
                        <button
                          onClick={() => handleMarkAsSold(property._id, 'sold')}
                          className="bg-gray-600 text-white px-3 py-1 rounded text-sm hover:bg-gray-700"
                        >
                          Mark as Sold
                        </button>
                      )}
                      {property.status === 'approved' && property.listingType === 'rent' && (
                        <button
                          onClick={() => handleMarkAsSold(property._id, 'rented')}
                          className="bg-gray-600 text-white px-3 py-1 rounded text-sm hover:bg-gray-700"
                        >
                          Mark as Rented
                        </button>
                      )}
                      <Link
                        to={`/properties/${property._id}`}
                        className="text-blue-600 hover:text-blue-800 text-sm"
                      >
                        View Details →
                      </Link>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MyProperties;
